Use `null` for optional refs to clear them. `undefined` is a no-op in updates.

```ts
await db.update(app.tasks, taskId, {
  projectId: null,
});
```

Use accessors for reactive query inputs.

```svelte
<script lang="ts">
  import { QuerySubscription } from "jazz-tools/svelte";

  let doneOnly = $state(false);
  const todosSub = new QuerySubscription(() => app.todos.where({ done: doneOnly }));

  const todos = $derived(todosSub.current);
</script>
```

```tsx
import { useAll } from "jazz-tools/solid";

const [doneOnly, setDoneOnly] = createSignal(false);

const todos = useAll(() => ({
  query: app.todos.where({ done: doneOnly() }),
}));
```

Use `db.batch(...)` for grouped optimistic writes that should appear together locally.

Use `db.transaction(...)` for writes that must be authority-accepted and become globally visible atomically.

```ts
// Optimistic UI
db.batch((batch) => {
  batch.insert(app.todos, { title: "Draft", done: false });
  batch.update(app.todos, firstTodoId, { done: true });
});

// Strongly consistent pair
const result = await db.transaction(async (tx) => {
  tx.update(app.todos, firstTodoId, { done: true });
  tx.insert(app.todos, { title: "Second", done: false });
});
await result.wait({ tier: "global" });
```

Define a self-referencing optional manager field on the same table.

```ts
import { schema as s } from "jazz-tools";

const schema = {
  employees: s.table({
    name: s.string(),
    managerId: s.ref("employees").optional(),
  }),
};

type AppSchema = s.Schema<typeof schema>;
export const app: s.App<AppSchema> = s.defineApp(schema);
```

`managerId` derives `manager` and reverse `employeesViaManager` relations automatically.

Use native column builders and the conventional `...Id` naming for refs.

```ts
const schema = {
  events: s.table({
    eventAt: s.date(),          // event timestamp
    fingerprint: s.binary(),     // small binary blob kept inline with the row
    projectId: s.ref("projects"),
  }),
};
```

Use `.optional()` on `projectId` only if an event can exist without a project.

Use the conventional `files` and `file_parts` tables and store the file on an `uploads` parent row (`upload.fileId`). Example:

```ts
const schema = {
  file_parts: s.table({ data: s.bytes() }),
  files: s.table({
    name: s.string().optional(),
    mimeType: s.string(),
    partIds: s.array(s.ref("file_parts")),
    partSizes: s.array(s.int()),
  }),
  uploads: s.table({
    owner_id: s.string(),
    label: s.string(),
    fileId: s.ref("files"),
  }),
};
```

Permissions: keep uploads private to owner and derive file access from the parent:

```ts
policy.uploads.allowRead.where({ owner_id: session.user_id });
policy.uploads.allowInsert.where({ owner_id: session.user_id });
policy.uploads.allowUpdate.where({ owner_id: session.user_id });
policy.uploads.allowDelete.where({ owner_id: session.user_id });

policy.files.allowInsert.where({});
policy.file_parts.allowInsert.where({});

policy.files.allowRead.where(allowedTo.readReferencing(policy.uploads, "fileId"));
policy.file_parts.allowRead.where(allowedTo.readReferencing(policy.files, "partIds"));
policy.files.allowDelete.where(allowedTo.deleteReferencing(policy.uploads, "fileId"));
policy.file_parts.allowDelete.where(allowedTo.deleteReferencing(policy.files, "partIds"));
```

Do not add general public reads/updates for files or parts; this keeps uploads private.

Use `tier: "edge"` on both upload creation and parent insert so success implies all chunks are durably written to edge:

```ts
const file = await db.createFileFromBlob(app, blob, { tier: "edge" });
await db.insert(app.uploads, { owner_id, label, fileId: file.id }).wait({ tier: "edge" });
```

For download, read in local-first mode first and handle `IncompleteFileDataError` explicitly:

```ts
let blob;
try {
  blob = await db.loadFileAsBlob(app, upload.fileId, { tier: "local" });
} catch (e) {
  if (e instanceof IncompleteFileDataError) {
    // surface "still syncing" state, or retry at stronger tier
    blob = await db.loadFileAsBlob(app, upload.fileId, { tier: "edge" });
  } else if (e instanceof FileNotFoundError) {
    // missing file metadata/state
  } else throw e;
}
```

Treat `IncompleteFileDataError` reasons (`invalid-file-record`, `missing-part`, `part-size-mismatch`) as recoverable sync states and keep file unavailable until fixed/completed.

Delete in dependency order while permissions still flow through `uploads -> files -> file_parts`:

```ts
const upload = await db.one(app.uploads.where({ id: uploadId }), { tier: "edge" });
if (!upload) return;

const file = await db.one(app.files.where({ id: upload.fileId }), { tier: "edge" });
if (file) {
  for (const partId of file.partIds) {
    await db.delete(app.file_parts, partId);
  }
  await db.delete(app.files, file.id);
}
await db.delete(app.uploads, upload.id);
```

Do **not** delete the parent upload first, because inherited `allowDelete` on file/parts depends on that relationship and will be lost, preventing cleanup and leaving orphans.

Use a strict projection layer around `QueryBuilder` and `Value` decoding, not ad-hoc positional reads.

```rust
struct TodoRow {
    id: ObjectId,
    title: String,
    done: bool,
    description: Option<String>,
}

fn decode_todo(row_id: ObjectId, values: &[Value]) -> Result<TodoRow, AppError> {
    if values.len() != 4 { return Err(AppError::SchemaDrift(values.len())); }
    let title = values[0].as_text().ok_or(AppError::InvalidRow("title"))?.to_string();
    let done = values[1].as_bool().ok_or(AppError::InvalidRow("done"))?;
    let description = match &values[2] {
        Value::Null => None,
        Value::Text(s) => Some(s.to_string()),
        _ => return Err(AppError::InvalidRow("description")),
    };

    Ok(TodoRow { id: row_id, title, done, description })
}
```

Then centralise every query:
- build a single `QueryBuilder` projection in a helper (`TodoColumnOrder`)
- run `client.query(builder.build())`
- map rows via `decode_todo`
- reuse a single writer API using `row_input!` and a helper that always returns `(ObjectId, ValueBatch, BatchId)`

Example insert:

```rust
let (id, _values, batch_id) = client.insert(
    "todos",
    row_input!("title" => title.as_str(), "done" => done, "description" => description),
)?;
client.wait_for_batch(batch_id, DurabilityTier::EdgeServer).await?;
```

Decode once, validate length and nullability once, and never depend on table-handle types that do not exist in Rust.

```ts
import { createDb, type Db } from "jazz-tools";
import { startLocalJazzServer, deploy } from "jazz-tools/testing";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { app } from "../schema";
import permissions from "../permissions";

describe("sync is deterministic by assertion", () => {
  let server: any;
  let alice: Db;
  let bob: Db;

  beforeEach(async () => {
    server = await startLocalJazzServer({ inMemory: true });
    await deploy({
      serverUrl: server.url,
      appId: server.appId,
      adminSecret: server.adminSecret,
      schema: app,
      permissions,
    });

    alice = await createDb({ appId: server.appId, serverUrl: server.url, adminSecret: server.adminSecret, driver: { type: "memory" } });
    bob = await createDb({ appId: server.appId, serverUrl: server.url, adminSecret: server.adminSecret, driver: { type: "memory" } });
  });

  afterEach(async () => {
    await alice.shutdown();
    await bob.shutdown();
    await server.stop();
  });

  it("syncs multiple rows; assertions do not depend on query order", async () => {
    const created = ["b", "a", "c"].map((title) => alice.insert(app.todos, { title, done: false }).wait({ tier: "edge" }));
    await Promise.all(created);

    await vi.waitFor(async () => {
      const rows = await bob.all(app.todos, { tier: "edge" });
      expect(rows).toHaveLength(3);

      const titles = rows.map((r) => r.title).sort();
      expect(titles).toEqual(["a", "b", "c"]);
    });
  });
});
```
- Use `tier: "edge"` waits before cross-client assertions.
- Sort `rows` (or apply explicit `.orderBy`) before comparing; never assert raw order unless order is the behaviour under test.

```ts
import { createPolicyTestApp } from "jazz-tools/testing";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { app } from "../schema";
import permissions from "../permissions";

describe("Alice row isolation", () => {
  let testApp: any;

  beforeEach(async () => {
    testApp = await createPolicyTestApp(app, permissions, expect);
  });

  afterEach(async () => {
    await testApp.shutdown();
  });

  it("denies Bob read and write access to Alice's row", async () => {
    const alice = testApp.as({ user_id: "alice", claims: {}, authMode: "local-first" });
    const bob = testApp.as({ user_id: "bob", claims: {}, authMode: "local-first" });

    const todo = alice.insert(app.todos, { title: "Secret", done: false }).value;

    await expect(bob.all(app.todos.where({ id: todo.id }))).resolves.toEqual([]);

    bob.expectDenied((db) => db.update(app.todos, todo.id, { title: "steal" }));
    bob.expectDenied((db) => db.delete(app.todos, todo.id));
  });
});
```
- If policy also gates create, add `bob.expectDenied((db)=>db.insert(app.todos,{title:"X"}))`.
- Keep denied reads asserted as `[]` (not an exception).
